import math, random


class DeclarativeMemory:
    """ACT-R declarative memory: stores chunks, retrieves by cue."""

    RETRIEVAL_THRESHOLD = -1.5  # Chunks below this activation cannot be retrieved
    LATENCY_FACTOR = 0.05       # F in latency = F * e^(-A) formula

    def __init__(self):
        self._chunks: dict[str, Chunk] = {}

    def add(self, chunk: Chunk) -> None:
        self._chunks[chunk.name] = chunk

    def retrieve(self, cue: dict[str, Any], t_now: float = 0.0) -> tuple[Chunk | None, float]:
        """
        Find the chunk whose slots best match the cue.
        Returns (chunk, latency_seconds) or (None, inf) if below threshold.
        """
        candidates = [
            c for c in self._chunks.values()
            if all(c.slots.get(k) == v for k, v in cue.items())
        ]
        if not candidates:
            return None, float("inf")

        # Pick highest activation
        best = max(candidates, key=lambda c: c.compute_base_level(t_now))
        activation = best.compute_base_level(t_now)

        if activation < self.RETRIEVAL_THRESHOLD:
            return None, float("inf")  # chunk exists but not retrievable

        # Retrieval latency (seconds): lower activation → slower
        latency = self.LATENCY_FACTOR * math.exp(-activation)
        best.record_retrieval(t_now)
        return best, latency


# Demo: retrieve arithmetic facts
dm = DeclarativeMemory()
for a, b, r in [(3, 4, 12), (7, 8, 56), (9, 6, 54)]:
    c = Chunk(f"mult-{a}-{b}", "multiplication-fact",
              {"operand1": a, "operand2": b, "result": r})
    c._retrieval_times = [50.0, 100.0, 150.0]  # practised 3 times
    dm.add(c)

chunk, lat = dm.retrieve({"operand1": 7, "operand2": 8}, t_now=200.0)
if chunk:
    print(f"Retrieved: {chunk.slots['result']} in {lat*1000:.1f}ms")
# Retrieved: 56 in ~50ms (exact depends on base-level)

class UtilityLearner:
    """
    ACT-R utility learning: production utilities evolve via RL.

    Utility(p) = P(p) * G - C(p)
        P(p)  = probability production p leads to goal success
        G     = value of achieving the goal
        C(p)  = expected cost (time) of production p

    Updated by: U(p) ← U(p) + α * (Rₜ - U(p))
    where Rₜ is the reward received at trial end.
    """

    def __init__(self, goal_value: float = 20.0, alpha: float = 0.2):
        self.G = goal_value
        self.alpha = alpha
        self.utilities: dict[str, float] = {}
        self.costs: dict[str, float] = {}

    def register(self, name: str, initial_utility: float = 0.0) -> None:
        self.utilities[name] = initial_utility
        self.costs[name] = 0.0

    def update(self, fired_productions: list[str], reward: float) -> None:
        """Update utilities for all productions fired in this trial."""
        for name in fired_productions:
            if name in self.utilities:
                old = self.utilities[name]
                self.utilities[name] = old + self.alpha * (reward - old)

    def best(self, candidates: list[str]) -> str | None:
        """Return the name with highest utility among candidates."""
        if not candidates:
            return None
        return max(candidates, key=lambda n: self.utilities.get(n, 0.0))


# Simulate learning over 5 trials
learner = UtilityLearner()
learner.register("strategy-A", 5.0)
learner.register("strategy-B", 5.0)

rewards = [20, 20, 5, 20, 20]   # strategy-A mostly succeeds
for i, r in enumerate(rewards):
    strategy = learner.best(["strategy-A", "strategy-B"])
    learner.update([strategy], r)
    print(f"Trial {i+1}: used {strategy}, reward={r}, "
          f"U(A)={learner.utilities['strategy-A']:.2f}, "
          f"U(B)={learner.utilities['strategy-B']:.2f}")
